agent_output:
{
  "domain_analysis": {
    "business_context": "Subscription billing platform managing lifecycle states (activation, renewal, cancellation, trials) with payment validation, retry logic, and tier-specific policies.",
    "bounded_context": "Subscription Billing & Lifecycle Management",
    "ubiquitous_language": [
      { "term": "Subscription", "definition": "A recurring billing agreement between a customer and the platform, progressing through states: trial, active, grace period, cancelled." },
      { "term": "Payment Method", "definition": "A stored instrument (card, bank account) used to collect subscription fees, carrying a valid/failed status." },
      { "term": "Billing Cycle", "definition": "The recurring period (e.g., monthly, annual) that defines when payment is collected." },
      { "term": "Renewal", "definition": "The automated attempt to charge and extend a subscription before the current billing cycle expires." },
      { "term": "Grace Period", "definition": "A time window after failed payment during which the subscription remains active before cancellation." },
      { "term": "Free Trial", "definition": "A time-limited subscription granted without payment, limited to one active instance per email address." },
      { "term": "Premium Tier", "definition": "A subscription level that confers enhanced billing tolerance (14-day grace period instead of 3-strike cancellation)." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A subscription cannot be activated with a failed payment method on file.",
      "invariant": true,
      "invariant_justification": "This is a state integrity constraint. Activating a subscription against a known-failed payment method means the system is entering a fundamentally corrupt state — it is promising service delivery while knowing it cannot collect revenue. This is not a policy a VP would loosen; it is a precondition for the subscription entity to be valid. Allowing it would create unbounded financial exposure and break the core contract between payment and service.",
      "testable_assertion": "ASSERT: Any attempt to transition a subscription to 'active' status MUST fail if the associated payment method's status is 'failed'."
    },
    {
      "id": "BR-2",
      "rule": "Subscriptions auto-renew 7 days before the billing cycle ends to allow retry time.",
      "invariant": false,
      "invariant_justification": "The 7-day lead time is a business policy tuned for operational convenience — it balances retry opportunity against premature charging. A VP could change this to 5 days or 10 days based on payment processor SLAs or customer feedback without corrupting system state. The system remains consistent regardless of the specific number of days chosen.",
      "testable_assertion": "ASSERT: The renewal process is triggered exactly RENEWAL_LEAD_DAYS (currently 7) before the billing cycle end date."
    },
    {
      "id": "BR-3",
      "rule": "After 3 failed renewal attempts, the subscription is automatically cancelled.",
      "invariant": false,
      "invariant_justification": "The retry count of 3 is a configurable business policy threshold. A product decision could change this to 2 or 5 attempts without breaking data integrity. What matters structurally is that *some* finite limit exists to prevent infinite retries — but the specific number is a policy knob, not a data consistency constraint.",
      "testable_assertion": "ASSERT: When a non-premium subscription accumulates MAX_FAILED_ATTEMPTS (currently 3) consecutive failed renewal charges, its status transitions to 'cancelled'."
    },
    {
      "id": "BR-4",
      "rule": "A cancelled subscription cannot be reactivated — customers must create a new subscription.",
      "invariant": true,
      "invariant_justification": "This is a state machine integrity constraint. The 'cancelled' state is terminal — it is an absorbing state in the subscription lifecycle. Allowing reactivation would break audit trails, corrupt billing history continuity, and create ambiguity about which billing cycle the customer is in. A new subscription creates a clean entity with its own lifecycle. Violating this corrupts the identity and history of the subscription aggregate.",
      "testable_assertion": "ASSERT: Any attempt to transition a subscription from 'cancelled' to 'active' MUST be rejected. The only valid path is creating a new Subscription entity."
    },
    {
      "id": "BR-5",
      "rule": "Premium tier subscribers get a 14-day grace period before cancellation instead of the 3-strike rule.",
      "invariant": false,
      "invariant_justification": "The 14-day grace window and the decision to use time-based vs. attempt-based logic for premium customers are both business policies reflecting a retention strategy for high-value customers. A VP could change this to 21 days, or revert premium to the strike-based model, without any data corruption. The system's structural integrity is unaffected by the specific grace period duration or the tier-differentiation strategy.",
      "testable_assertion": "ASSERT: When a premium-tier subscription has a failed renewal, cancellation is deferred for PREMIUM_GRACE_DAYS (currently 14) from the first failure date, rather than applying the failed-attempt counter."
    },
    {
      "id": "BR-6",
      "rule": "Free trial subscriptions cannot have more than one active trial per email address at any time.",
      "invariant": true,
      "invariant_justification": "This is a uniqueness constraint protecting data integrity and preventing abuse. If two active trials exist for the same email, the system is in a corrupt state — it cannot reason about which trial is authoritative, trial-to-paid conversion tracking breaks, and the business is exposed to systematic fraud. This is analogous to a unique constraint on a primary identifier; it is not a policy preference but a consistency requirement for the trial entity to be meaningful.",
      "testable_assertion": "ASSERT: Creating a new trial subscription MUST fail if an active trial subscription already exists for the same email address. The system must enforce this as a uniqueness constraint."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A customer with a payment method in 'failed' status",
      "when": "They attempt to activate a new subscription",
      "then": "The system rejects activation and returns an error indicating the payment method must be resolved first"
    },
    {
      "id": "AC-2",
      "given": "An active subscription with a billing cycle ending in 7 days",
      "when": "The renewal scheduler runs",
      "then": "A renewal charge is initiated against the customer's payment method"
    },
    {
      "id": "AC-3",
      "given": "A non-premium subscription with 2 prior consecutive failed renewal attempts",
      "when": "The 3rd renewal attempt fails",
      "then": "The subscription status transitions to 'cancelled' and the customer is notified"
    },
    {
      "id": "AC-4",
      "given": "A subscription in 'cancelled' status",
      "when": "Any attempt is made to reactivate it (via API, admin panel, or automated process)",
      "then": "The system rejects the state transition and requires creation of a new subscription"
    },
    {
      "id": "AC-5",
      "given": "A premium-tier subscription with a failed renewal on day 0",
      "when": "14 days elapse without a successful payment",
      "then": "The subscription is automatically cancelled on day 14"
    },
    {
      "id": "AC-6",
      "given": "A premium-tier subscription with a failed renewal on day 0",
      "when": "A successful payment is collected on day 10",
      "then": "The subscription remains active and the grace period is cleared"
    },
    {
      "id": "AC-7",
      "given": "An email address (e.g., user@example.com) with an active free trial subscription",
      "when": "A second free trial is requested for the same email",
      "then": "The system rejects the request and returns an error indicating an active trial already exists"
    }
  ],

  "edge_cases": [
    { "scenario": "Payment method fails *after* subscription activation but before first renewal", "expected_behavior": "Subscription remains active until renewal is attempted; BR-1 only gates activation, not ongoing status. The renewal retry/cancellation flow (BR-3 or BR-5) handles post-activation failures." },
    { "scenario": "Premium subscriber is downgraded to standard tier mid-grace-period", "expected_behavior": "Must be explicitly defined — does the 14-day grace period continue or does the 3-strike rule immediately apply? This is an edge case requiring product decision." },
    { "scenario": "Customer's payment method transitions from failed to valid during the renewal retry window", "expected_behavior": "Next retry attempt should succeed against the now-valid payment method, resetting the failure counter and keeping the subscription active." },
    { "scenario": "Free trial expires and customer starts a paid subscription, then cancels — can they start a new trial?", "expected_behavior": "BR-6 says one active trial per email 'at any time.' Once the original trial is no longer active (expired or converted), a new trial could technically be created. Product should clarify if 'ever' or 'at any time' is intended." },
    { "scenario": "Renewal is triggered 7 days before cycle end, but cycle end date is changed (e.g., plan upgrade mid-cycle)", "expected_behavior": "Renewal lead time should recalculate based on the new cycle end date. If the new end date is less than 7 days away, renewal should trigger immediately." },
    { "scenario": "All 3 failed attempts occur on the same day (e.g., rapid retries)", "expected_behavior": "The 3-strike rule should still apply — the count is based on attempts, not calendar days. Subscription is cancelled after the 3rd failure regardless of timing." }
  ],

  "business_impact": {
    "financial": "BR-1 prevents revenue leakage from activating subscriptions that can never collect. BR-3/BR-5 balance revenue recovery (retry window) against carrying cost of delinquent accounts. The 7-day lead time (BR-2) directly affects cash flow timing and dunning success rates.",
    "operational": "The invariant/policy split enables product teams to tune retry counts and grace periods without engineering changes, while protecting system integrity constraints that require code-level enforcement.",
    "user": "Premium grace period (BR-5) improves retention for high-value customers. The no-reactivation rule (BR-4) creates friction but ensures clean billing history. Trial uniqueness (BR-6) prevents abuse but must have clear messaging to avoid frustrating legitimate users.",
    "risk": "Misclassifying BR-4 (cancelled = terminal) as a soft policy could lead to reactivation bugs that corrupt billing audit trails. Misclassifying BR-2 (7-day lead time) as an invariant would create unnecessary rigidity in adapting to payment processor changes.",
    "stakeholders_affected": [
      { "group": "Customers (Standard Tier)", "impact": "Subject to 3-strike cancellation; must create new subscription after cancellation" },
      { "group": "Customers (Premium Tier)", "impact": "14-day grace period provides more tolerance for payment issues" },
      { "group": "Finance/Revenue Team", "impact": "Renewal timing and retry policies directly affect MRR recovery rates and churn metrics" },
      { "group": "Customer Support", "impact": "Must handle inquiries about why cancelled subscriptions cannot be reactivated and guide customers to create new ones" },
      { "group": "Fraud/Trust & Safety", "impact": "Trial uniqueness constraint is a primary defense against trial abuse at scale" }
    ]
  },

  "confidence": {
    "level": 72,
    "reasoning": "The spec is reasonably clear on most rules, but contains ambiguity around the interaction between premium grace period and the standard retry model (are retries still attempted during the 14 days?), and the trial uniqueness scope ('at any time' vs 'ever'). No access to existing codebase to validate against implementation. The invariant classifications are high-confidence based on the heuristic (state integrity vs policy knobs).",
    "high_confidence_areas": [
      "BR-1 classification as invariant (failed payment blocks activation)",
      "BR-4 classification as invariant (cancelled is terminal state)",
      "BR-6 classification as invariant (trial uniqueness constraint)",
      "BR-2 and BR-3 classification as policy (configurable thresholds)"
    ],
    "low_confidence_areas": [
      "Whether premium grace period replaces or supplements the retry mechanism",
      "Whether 'one active trial per email at any time' means concurrent or lifetime",
      "Interaction between tier changes and in-flight grace periods"
    ],
    "assumptions": [
      "Payment method status is binary (valid/failed) and is evaluated at activation time",
      "The 3-strike counter resets on a successful payment",
      "Premium grace period is time-based and replaces the attempt-count model entirely for that tier",
      "Trial uniqueness is enforced at the point of creation, not retroactively"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec says premium subscribers get a '14-day grace period instead of the 3-strike rule.' It is unclear whether payment retries still occur during the 14-day window, or if the system simply waits 14 days with no retry attempts. This affects both implementation and the customer experience.",
      "affected_stakeholders": ["Premium Customers", "Finance/Revenue Team", "Engineering"],
      "options": ["A: Retries still occur during the 14-day window; cancellation happens at day 14 if none succeed", "B: No retries; the customer must self-serve update their payment method within 14 days"],
      "recommendation": "Option A — retries during grace period maximize recovery rate while the grace window provides a longer runway. This aligns with standard dunning practices in subscription billing."
    },
    {
      "type": "ambiguity",
      "description": "The trial rule says 'no more than one active trial per email at any time.' Does this mean a customer who completed a trial (expired or converted to paid) can start another trial in the future? Or is it a lifetime limit of one trial per email?",
      "affected_stakeholders": ["Customers", "Growth/Marketing Team", "Fraud/Trust & Safety"],
      "options": ["A: One trial per email lifetime (prevents all re-trial abuse)", "B: One concurrent active trial, but previous trials don't block future ones (allows win-back trials)"],
      "recommendation": "The phrase 'at any time' suggests concurrency, not lifetime — Option B. But product must confirm, as this has significant growth and fraud implications."
    }
  ],

  "rejection_reasons": []
}

